const data = $input.first().json;

let score = 0;
let reasons = [];

// BUDGET SCORING (0-40 pts)
const budget = parseInt(data.budget.replace(/[^0-9]/g, '')) || 0;
if (budget >= 300000) {
  score += 40;
  reasons.push('Alto presupuesto (+40)');
} else if (budget >= 150000) {
  score += 25;
  reasons.push('Presupuesto medio (+25)');
} else {
  score += 10;
  reasons.push('Presupuesto bajo (+10)');
}

// ZONE SCORING (0-30 pts)
const hotZones = ['ruzafa', 'eixample', 'l\'eixample', 'el carmen', 'ciutat vella', 'extramurs'];
const zone = data.zone.toLowerCase();
if (hotZones.some(z => zone.includes(z))) {
  score += 30;
  reasons.push('Zona premium (+30)');
} else if (zone.includes('valencia')) {
  score += 15;
  reasons.push('Valencia ciudad (+15)');
} else {
  score += 5;
  reasons.push('Zona exterior (+5)');
}

// PROPERTY TYPE SCORING (0-20 pts)
const type = data.property_type.toLowerCase();
if (type.includes('compra') || type.includes('piso') || type.includes('chalet') || type.includes('atico')) {
  score += 20;
  reasons.push('Compra (+20)');
} else if (type.includes('alquiler')) {
  score += 10;
  reasons.push('Alquiler (+10)');
} else {
  score += 5;
  reasons.push('Tipo no especificado (+5)');
}

// URGENCY SCORING (0-10 pts)
const urgency = (data.urgency || '').toLowerCase();
if (urgency.includes('urgent') || urgency.includes('inmedia') || urgency.includes('cuanto antes')) {
  score += 10;
  reasons.push('Urgente (+10)');
}

// PRIORITY TIER
let tier, tierLabel, tierEmoji;
if (score >= 70) {
  tier = 'HOT';
  tierLabel = 'Lead Caliente';
  tierEmoji = '🔥';
} else if (score >= 40) {
  tier = 'WARM';
  tierLabel = 'Lead Tibio';
  tierEmoji = '⚡';
} else {
  tier = 'COLD';
  tierLabel = 'Lead Frío';
  tierEmoji = '❄️';
}

return [{
  json: {
    ...data,
    score,
    tier,
    tierLabel,
    tierEmoji,
    scoreReasons: reasons.join(', ')
  }
}];

